            m_rs = cv2.resize(mask, (new_w, new_h), interpolation=cv2.INTER_NEAREST)
            if m_rs.dtype != mask.dtype:
                if mask.dtype == np.bool_:
                    m_rs = (m_rs > 0)
                else:
                    m_rs = (m_rs > 0).astype(mask.dtype) * (255 if mask.dtype == np.uint8 else 1)
            sample["mask"] = m_rs
        return (new_h, new_w)

