import numpy as np
def cosine_distance(a, b):
    if a.shape[-1] != b.shape[-1]:
        return ValueError
    dist = np.dot(a, b.T) / (np.linalg.norm(a, axis=-1) * np.linalg.norm(b, axis=-1))
    return dist

