import numpy as np
import torch
def numpy_image_to_torch(image: np.ndarray) -> torch.Tensor:
    if image.ndim == 3:
        image = image.transpose((2, 0, 1))  # HxWxC to CxHxW
    elif image.ndim == 2:
        image = image[None]  # add channel axis
    else:
        return ValueError
    return torch.tensor(image / 255.0, dtype=torch.float)

