                den = ((fv - fm) ** 2).sum()
                if den.abs() < 1e-12:
                    c = fv.new_tensor(0.0)
                    d = ym
                else:
                    c = num / den
                    d = ym - c * fm
                # r2
                ss_res = ((yv - (c * fv + d)) ** 2).sum()
                ss_tot = ((yv - ym) ** 2).sum()
                if ss_tot == 0:
                    r2 = 1.0 if ss_res == 0 else 0.0
                else:
                    r2 = 1.0 - (ss_res / ss_tot).item()
                return c.item() if not isinstance(c, float) else c, d.item() if not isinstance(d, float) else d, float(r2)
            else:
                ym = yv.mean()
                fm = fv.mean()
                num = ((yv - ym) * (fv - fm)).sum()
                den = ((fv - fm) ** 2).sum()
                if abs(den) < 1e-12:
                    c = 0.0
                    d = ym
                else:
                    c = num / den
                    d = ym - c * fm
                ss_res = ((yv - (c * fv + d)) ** 2).sum()
                ss_tot = ((yv - ym) ** 2).sum()
                if ss_tot == 0:
                    r2 = 1.0 if ss_res == 0 else 0.0
                else:
                    r2 = 1.0 - ss_res / ss_tot
                return c, d, float(r2)
        a_lo, a_hi = float(a_range[0]), float(a_range[1])
        b_lo, b_hi = float(b_range[0]), float(b_range[1])
        best = (None, None, None, None, -1e9)
        for it in range(iteration):
