import os.path
def path_spliter(path: str):
    res = []
    if path == '':
        return []
    while path != '' and path != '/':
        res.append(os.path.split(path)[1])
        path = os.path.split(path)[0]
    if path != '':
        res.append(path)
    return res[::-1]

