            k = best_k
        else:
            raise ValueError("direction must be 'standard', 'down' or 'up'")
        result = k * a
        s = format(a, 'f')
        if '.' in s:
            dec = len(s.split('.')[1].rstrip('0'))
        else:
            dec = 0
        fmt = f"{{0:.{dec}f}}"
        return float(fmt.format(result))

