def reshape_weight_task_tensors(task_tensors, weights):
    import torch
    def reshape_weight_task_tensors(task_tensors, weights):
        if not isinstance(task_tensors, torch.Tensor) or not isinstance(weights, torch.Tensor):
            raise TypeError("Both task_tensors and weights must be torch.Tensor")
