def reshape_tensor(x, heads):
    import torch
    def reshape_tensor(x, heads):
        if not isinstance(x, torch.Tensor):
            raise ValueError("x must be a torch.Tensor")
        if not isinstance(heads, int) or heads <= 0:
            raise ValueError("heads must be a positive integer")
        if x.dim() != 3:
            raise ValueError("x must be 3-dimensional (batch, length, width)")
        batch, length, width = x.shape
        if width % heads != 0:
            raise ValueError("width must be divisible by heads")
        dim_per_head = width // heads
        # reshape to (batch, length, heads, dim_per_head)
        y = x.reshape(batch, length, heads, dim_per_head)
        # permute to (batch, heads, length, dim_per_head)
        y = y.permute(0, 2, 1, 3).contiguous()
        # merge batch and heads -> (batch*heads, length, dim_per_head)
        return y.view(batch * heads, length, dim_per_head)

