def remove_scale_from_camera_pose(pose_matrix):
    import numpy as np
    def remove_scale_from_camera_pose(pose_matrix):
        pose = np.array(pose_matrix, dtype=float, copy=True)
        if pose.shape != (4, 4):
            raise ValueError("pose_matrix must be 4x4")
        M = pose[:3, :3]
        try:
            U, S, Vt = np.linalg.svd(M)
            R = U @ Vt
            if np.linalg.det(R) < 0:
                U[:, -1] *= -1
                R = U @ Vt
        except np.linalg.LinAlgError:
            # fallback: column-normalize
            R = M.copy().astype(float)
            for i in range(3):
                n = np.linalg.norm(R[:, i])
                if n > 0:
                    R[:, i] = R[:, i] / n
            # enforce orthogonality via SVD fallback
            U, _, Vt = np.linalg.svd(R)
            R = U @ Vt
            if np.linalg.det(R) < 0:
                U[:, -1] *= -1
                R = U @ Vt
        pose[:3, :3] = R
        return pose

