            Q = U @ Vt
            if np.linalg.det(Q) < 0:
                U[:, -1] *= -1
                Q = U @ Vt
        pose[:3, :3] = Q
        return pose

def window_partition(x: torch.Tensor, window_size: Sequence[int]):
    import torch
    from typing import Sequence
    def window_partition(x: torch.Tensor, window_size: Sequence[int]):
        win_h, win_w = int(window_size[0]), int(window_size[1])
        if x.dim() != 4:
            raise ValueError("Input must be 4D (B,H,W,C).")
        B, H, W, C = x.shape
        if H % win_h != 0 or W % win_w != 0:
            raise ValueError("H and W must be divisible by window sizes.")
        out_list = []
        for b in range(B):
            for i in range(0, H, win_h):
                for j in range(0, W, win_w):
                    out_list.append(x[b, i:i+win_h, j:j+win_w, :])
        if not out_list:
            return x.new_empty((0, win_h, win_w, C))
        out = torch.stack(out_list, dim=0)
        return out

