def top_p_sample(prob_dist: torch.Tensor, top_p: float) -> torch.Tensor:
    import torch
    def top_p_sample(prob_dist: torch.Tensor, top_p: float) -> torch.Tensor:
        if prob_dist.dim() != 2:
            raise ValueError("prob_dist must be 2D (batch_size, vocab_size)")
        probs = prob_dist.clone()
        if top_p >= 1.0:
            return probs
        if top_p <= 0.0:
            out = torch.zeros_like(probs)
            out[torch.arange(probs.size(0)), probs.argmax(dim=1)] = 1.0
            return out
        out = torch.zeros_like(probs)
        for i in range(probs.size(0)):
            row = probs[i]
            sorted_vals, sorted_idx = torch.sort(row, descending=True)
            cumsum = torch.cumsum(sorted_vals, dim=0)
            keep_mask_sorted = (cumsum - sorted_vals) < top_p
            keep_idx = sorted_idx[keep_mask_sorted]
            kept = row[keep_idx]
            if kept.sum() == 0:
                max_idx = int(row.argmax().item())
                out[i, max_idx] = 1.0
            else:
                out[i, keep_idx] = kept / kept.sum()
        return out

