def remove_outliers(arr, num_std_devs=2):
    import numpy as np
    def remove_outliers(arr, num_std_devs=2):
        """
        Remove outliers using median and MAD (scaled to be comparable to std).
        """
        x = np.asarray(arr)
        if x.size == 0:
            return np.array([])
        x_flat = x.ravel().astype(float)
        # Exclude NaNs from calculations and results
        good = ~np.isnan(x_flat)
        if not np.any(good):
            return np.array([])
        vals = x_flat[good]
        med = np.median(vals)
        mad = np.median(np.abs(vals - med))
        # scale factor to make MAD comparable to std for normal distribution
        scaled_mad = mad * 1.4826
        if scaled_mad == 0:
            # fallback to simple median distance filter
            mask_vals = np.abs(vals - med) <= (num_std_devs * 1e-12)
        else:
            mask_vals = np.abs(vals - med) <= (num_std_devs * scaled_mad)
        return vals[mask_vals]

