    import numpy as np
    def remove_outliers(arr, num_std_devs=2):
        """
        Iteratively remove outliers based on mean/std until stable or max iterations reached.
        """
        x = np.asarray(arr)
        if x.size == 0:
            return np.array([])
        x_flat = x.ravel().astype(float)
        data = x_flat[~np.isnan(x_flat)]
        if data.size == 0:
            return np.array([])
        prev_len = -1
        for _ in range(10):
            mean = data.mean()
            std = data.std()
            if std == 0:
                break
            lower = mean - num_std_devs * std
            upper = mean + num_std_devs * std
            data = data[(data >= lower) & (data <= upper)]
            if data.size == prev_len:
                break
            prev_len = data.size
            if data.size == 0:
                break
        return data

