        q1 = np.percentile(vals, 25)
        q3 = np.percentile(vals, 75)
        iqr = q3 - q1
        if iqr == 0:
            # fallback to mean/std
            mean = vals.mean()
            std = vals.std()
            if std == 0:
                return vals
            lower = mean - num_std_devs * std
            upper = mean + num_std_devs * std
        else:
            lower = q1 - num_std_devs * iqr
            upper = q3 + num_std_devs * iqr
        mask = (vals >= lower) & (vals <= upper)
        return vals[mask]

