def deriv_fitting_matrix(degree, t_end=1.0):
    import numpy as np
    import math
    def deriv_fitting_matrix(degree, t_end=1.0):
        if degree % 2 != 0:
            raise AssertionError("degree must be even")
        n = degree // 2
        m = degree + 1
        A = np.zeros((m, m), dtype=float)
        # Precompute factorials 0..degree
        fact = [1.0] * (degree + 1)
        for i in range(1, degree + 1):
            fact[i] = fact[i - 1] * i
        # Rows: derivatives at t=0 for orders 0..n-1
        for r in range(0, n):
            # derivative r at 0 picks only coefficient of t^r multiplied by r!
            A[r, r] = fact[r]
        # Rows: derivatives at t_end for orders 0..n
        for r in range(0, n + 1):
            row_idx = n + r
            for j in range(r, degree + 1):
                A[row_idx, j] = fact[j] / fact[j - r] * (t_end ** (j - r))
        return A

