def generate_linear_parameters(start, stop, num):
    from itertools import accumulate, chain, repeat, islice
    def generate_linear_parameters(start, stop, num):
        num = int(num)
        if num <= 0:
            return []
        if num == 1:
            return [float(start)]
        start_f = float(start)
        stop_f = float(stop)
        step = (stop_f - start_f) / (num - 1)
        seq = accumulate(chain([start_f], repeat(step, max(0, num-1))))
