def cosine_similarity(X: Union[List[List[float]], List[np.ndarray], np.ndarray], Y: Union[List[List[float]], List[np.ndarray], np.ndarray]) -> np.ndarray:
    import numpy as np
    from typing import List, Union
    def cosine_similarity(X: Union[List[List[float]], List[np.ndarray], np.ndarray], Y: Union[List[List[float]], List[np.ndarray], np.ndarray]) -> np.ndarray:
        X = np.asarray(X, dtype=float)
        Y = np.asarray(Y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(1, -1)
        if Y.ndim == 1:
            Y = Y.reshape(1, -1)
        if X.shape[1] != Y.shape[1]:
            raise ValueError("X and Y must have the same number of columns.")
        m, n = X.shape[0], Y.shape[0]
        out = np.zeros((m, n), dtype=float)
        for i in range(m):
            xi = X[i]
            xi_norm = np.linalg.norm(xi)
            if xi_norm == 0:
                continue
            for j in range(n):
                yj = Y[j]
                yj_norm = np.linalg.norm(yj)
                if yj_norm == 0:
                    continue
                out[i, j] = np.dot(xi, yj) / (xi_norm * yj_norm)
        return out

def clean_folder_name(folder_name: str) -> str:
    import unicodedata
    def clean_folder_name(folder_name: str) -> str:
        if folder_name is None:
            return ""
        # Normalize unicode
        name = unicodedata.normalize('NFKC', folder_name)
        out_chars = []
        forbidden = set('<>:"/\\|?*')
        for ch in name:
            cat = unicodedata.category(ch)
            # Category starting with C are control/other - disallow; also disallow forbidden ascii set
            if ch in forbidden or cat.startswith('C'):
                out_chars.append('_')
            else:
                out_chars.append(ch)
        sanitized = ''.join(out_chars)
        # Replace trailing spaces or dots with underscores
        if sanitized and sanitized[-1] in (' ', '.'):
            idx = len(sanitized) - 1
            while idx >= 0 and sanitized[idx] in (' ', '.'):
                idx -= 1
            sanitized = sanitized[:idx+1] + ('_' * (len(sanitized) - idx - 1))
        return sanitized

