def repeat_to_batch_size(tensor, batch_size):
    import math
    import torch
    def repeat_to_batch_size(tensor, batch_size):
        if batch_size < 0:
            raise ValueError("batch_size must be non-negative")
        if not isinstance(tensor, torch.Tensor):
            tensor = torch.tensor(tensor)
        # Treat scalar as a single-element batch
        if tensor.dim() == 0:
            tensor = tensor.unsqueeze(0)
        n = tensor.size(0)
        if n == batch_size:
            return tensor
        if n == 0:
            if batch_size == 0:
                return tensor
            raise ValueError("Cannot repeat an empty tensor along the first dimension")
        if n > batch_size:
            return tensor[:batch_size]
        repeats = math.ceil(batch_size / n)
        repeated = torch.cat([tensor] * repeats, dim=0)
        return repeated[:batch_size]

