def rotate_half(x):
    import torch
    def rotate_half(x):
        if not isinstance(x, torch.Tensor):
            x = torch.tensor(x)
        nd = x.dim()
        last = x.size(-1)
        if last % 2 != 0:
            raise ValueError("Last dimension must be a multiple of 2")
        if last == 0:
            return x.clone()
        pairs = last // 2
        orig_shape = x.shape
        y = x.reshape(*orig_shape[:-1], pairs, 2)
        # rotation matrix for 90 degrees CCW: [[0, -1],[1, 0]]
        device = x.device
        dtype = x.dtype
        rot = torch.tensor([[0, -1], [1, 0]], device=device, dtype=dtype)
        # matrix multiply last two dims
        y_rot = torch.matmul(y, rot.t())
        return y_rot.reshape(orig_shape)

