def mse_to_psnr(mse):
    import numpy as np
    def mse_to_psnr(mse):
        """
        Simple implementation:
        - Raises ValueError if mse == 0 or mse < 0
        - Uses np.log for the log10 conversion
        """
        if mse == 0:
            raise ValueError("MSE is zero, PSNR is undefined.")
        if mse < 0:
            raise ValueError("MSE must be non-negative.")
        # Use natural log to compute log10 via change of base
        return -10.0 * np.log(mse) / np.log(10.0)

