def mse_to_psnr(mse):
    import numpy as np
    def mse_to_psnr(mse):
        """
        Vectorized implementation that accepts scalars, lists, or numpy arrays.
        Raises ValueError if any mse value equals zero or is negative.
        """
        arr = np.asarray(mse)
        if arr.size == 0:
            raise ValueError("Empty input")
        if np.any(arr == 0):
            raise ValueError("MSE contains zero value(s), PSNR undefined.")
        if np.any(arr < 0):
            raise ValueError("MSE must be non-negative.")
