def his_match(src, dst):
    import numpy as np
    def his_match(src, dst):
        src_u = np.clip(src, 0, 255).astype(np.uint8)
        dst_u = np.clip(dst, 0, 255).astype(np.uint8)
        out = np.empty_like(dst_u, dtype=np.uint8)
        for ch in range(3):
            src_ch = src_u[..., ch].ravel()
            dst_ch = dst_u[..., ch].ravel()
            src_hist = np.bincount(src_ch, minlength=256).astype(np.float64)
            dst_hist = np.bincount(dst_ch, minlength=256).astype(np.float64)
            src_cdf = np.cumsum(src_hist)
            dst_cdf = np.cumsum(dst_hist)
            if src_cdf[-1] == 0:
                src_cdf = np.linspace(0, 1, 256)
            else:
                src_cdf = src_cdf / src_cdf[-1]
            if dst_cdf[-1] == 0:
                dst_cdf = np.linspace(0, 1, 256)
            else:
                dst_cdf = dst_cdf / dst_cdf[-1]
            mapping = np.zeros(256, dtype=np.uint8)
            for v in range(256):
                target = dst_cdf[v]
                idx = np.searchsorted(src_cdf, target)
                if idx == 0:
                    mapping[v] = 0
                elif idx >= 256:
                    mapping[v] = 255
                else:
                    # pick nearest of idx-1 and idx
                    if abs(src_cdf[idx] - target) < abs(src_cdf[idx-1] - target):
                        mapping[v] = idx
                    else:
                        mapping[v] = idx-1
            out[..., ch] = mapping[dst_u[..., ch]]
        return out.astype(np.float64)

