            hs = np.bincount(s, minlength=256).astype(np.float64)
            hd = np.bincount(d, minlength=256).astype(np.float64)
            cs = np.cumsum(hs).astype(np.float64)
            cd = np.cumsum(hd).astype(np.float64)
            if cs[-1] == 0:
                cs = np.linspace(0, 1, 256)
            else:
                cs = cs / cs[-1]
            if cd[-1] == 0:
                cd = np.linspace(0, 1, 256)
            else:
                cd = cd / cd[-1]
            # build full cost matrix and take argmin (vectorized)
            diff = np.abs(cd[:, None] - cs[None, :])
            mapping = np.argmin(diff, axis=1).astype(np.uint8)
            out[..., ch] = mapping[dst_u[..., ch]]
        return out.astype(np.float64)

