def disjoint_cycles(perm):
    def disjoint_cycles(perm):
        n = len(perm)
        if n == 0:
            return []
        # detect 1-based permutation (values 1..n)
        if set(perm) == set(range(1, n + 1)):
            domain = [i + 1 for i in range(n)]
            mapping = {i + 1: perm[i] for i in range(n)}
        else:
            domain = list(range(n))
            mapping = {i: perm[i] for i in range(n)}
        visited = set()
        cycles = []
        for start in domain:
            if start in visited:
                continue
            cur = start
            cycle = []
            while cur not in visited:
                visited.add(cur)
                cycle.append(cur)
                cur = mapping[cur]
            cycles.append(cycle)
        return cycles

