def smooth_pose_seq(pose_seq, window_size=5):
    import numpy as np
    def smooth_pose_seq(pose_seq, window_size=5):
        pose_seq = np.asarray(pose_seq, dtype=float)
        if pose_seq.size == 0:
            return pose_seq.copy()
        n = pose_seq.shape[0]
        half = window_size // 2
        out = np.empty_like(pose_seq)
        for i in range(n):
            start = max(0, i - half)
            end = min(n, i + half + 1)
            out[i] = pose_seq[start:end].mean(axis=0)
        return out

