def general_detokenize(string):
    import re
    def general_detokenize(string):
        if string is None:
            return ""
        s = string.strip()
        # First break into whitespace-separated tokens (preserve punctuation tokens)
        rough = re.split(r'(\s+)', s)  # keep spaces to reconstruct intelligently
        parts = []
        # Merge tokens so that punctuation is separated
        for piece in rough:
            if piece.isspace():
                parts.append(piece)
            else:
                # separate punctuation stuck to words
                split_pieces = re.findall(r"[A-Za-z0-9]+(?:'[A-Za-z0-9]+)*|[^\w\s]", piece)
                if not split_pieces:
                    parts.append(piece)
                else:
                    # add spaces between extracted tokens to be processed later
                    for sp in split_pieces:
                        parts.append(sp)
                        parts.append(' ')
                    if parts:
                        parts.pop()  # remove trailing space from this chunk
        # Now build final string by applying rules on adjacency
        out = []
        i = 0
        while i < len(parts):
            tok = parts[i]
            if tok.isspace():
                # decide whether to keep a single space
                # peek next non-space token
                j = i + 1
                while j < len(parts) and parts[j].isspace():
                    j += 1
                if j >= len(parts):
                    i = j
                    continue
                next_tok = parts[j]
                prev_tok = out[-1] if out else ''
                # omit space if next is closing punctuation or prev is opening punctuation or next starts with apostrophe
                if next_tok in '.,!?;:%)]}\'"' or (prev_tok and prev_tok[-1] in '([{<"\'' ) or next_tok.startswith("'"):
                    i = j
                    continue
                # else ensure single space if appropriate
                if out and out[-1] and not out[-1].endswith(' '):
                    out.append(' ')
                i = j
                continue
            else:
                # token content
                if out and out[-1] == ' ':
                    out.append(tok)
                elif not out:
                    out.append(tok)
                else:
                    # If token is closing punctuation or contraction, attach to previous
                    if tok in '.,!?;:%)]}\'"' or tok.startswith("'"):
                        out[-1] = out[-1] + tok
                    else:
                        # otherwise add with a space
                        out.append(' ')
                        out.append(tok)
                i += 1
                continue
        result = ''.join(out).strip()
        # Final fixes: contractions may be separated with spaces in edge cases
        result = re.sub(r"\b([A-Za-z]+)\s+(n't|'re|'ve|'ll|'d|'m|'s)\b", r"\1\2", result, flags=re.IGNORECASE)
        # clean up multi spaces and spacing around ellipses
        result = re.sub(r'\s{2,}', ' ', result)
        result = re.sub(r'\.\s*\.\s*\.', '...', result)
        return result

