                raise ValueError("Input must be a square matrix")
            try:
                return torch.linalg.inv(mat)
            except RuntimeError:
                # fallback to Moore-Penrose pseudo-inverse via SVD
                u, s, vh = torch.linalg.svd(mat)
                # invert non-zero singular values
                tol = max(mat.shape) * s.max().abs() * torch.finfo(s.dtype).eps
                s_inv = torch.where(s.abs() > tol, 1.0 / s, torch.zeros_like(s))
                return (vh.transpose(-2, -1) * s_inv.unsqueeze(-2)) @ u.transpose(-2, -1)
        else:
            raise ValueError("Input must be a torch.Tensor or np.ndarray")

