def inv(mat):
    import numpy as np
    import torch
    def _gauss_jordan_inverse_numpy(a):
        n = a.shape[0]
        A = a.astype(float).copy()
        I = np.eye(n, dtype=float)
        for i in range(n):
            # Find pivot
            max_row = np.argmax(np.abs(A[i:, i])) + i
            if np.isclose(A[max_row, i], 0.0):
                raise np.linalg.LinAlgError("Matrix is singular.")
            # Swap rows
            if max_row != i:
                A[[i, max_row]] = A[[max_row, i]]
                I[[i, max_row]] = I[[max_row, i]]
            # Normalize pivot row
            pivot = A[i, i]
            A[i] = A[i] / pivot
            I[i] = I[i] / pivot
            # Eliminate other rows
            for j in range(n):
                if j != i:
                    factor = A[j, i]
                    A[j] -= factor * A[i]
                    I[j] -= factor * I[i]
        return I
    def inv(mat):
        if isinstance(mat, np.ndarray):
            if mat.ndim != 2 or mat.shape[0] != mat.shape[1]:
                raise ValueError("Input must be a square matrix")
            return _gauss_jordan_inverse_numpy(mat)
        elif isinstance(mat, torch.Tensor):
            if mat.ndim != 2 or mat.shape[0] != mat.shape[1]:
                raise ValueError("Input must be a square matrix")
            # perform inversion via numpy Gauss-Jordan on CPU, preserve device/dtype
            device = mat.device
            dtype = mat.dtype
            np_mat = mat.detach().to('cpu').numpy()
            np_inv = _gauss_jordan_inverse_numpy(np_mat)
            return torch.from_numpy(np_inv).to(device=device, dtype=dtype)
        else:
            raise ValueError("Input must be a torch.Tensor or np.ndarray")

